// mux.c - تجميع حزم من عدة streams في ملف خرج واحد
#include <libavformat/avformat.h>
#include <stdio.h>

int main(void) {
    AVFormatContext *out_fmt = NULL;
n    const AVOutputFormat *out_fmt_desc = av_guess_format("output.mp4", NULL, "video/mp4");
    avformat_alloc_output_context2(&out_fmt, out_fmt_desc, NULL, "output.mp4");
n
    // إنشاء streams في ملف الخرج
    AVStream *video_stream = avformat_new_stream(out_fmt, NULL);
    video_stream->time_base = (AVRational){1, 25};
    video_stream->codecpar->codec_type = AVMEDIA_TYPE_VIDEO;
    video_stream->codecpar->codec_id = AV_CODEC_ID_H264;

    AVStream *audio_stream = avformat_new_stream(out_fmt, NULL);
    audio_stream->time_base = (AVRational){1, 44100};
    audio_stream->codecpar->codec_type = AVMEDIA_TYPE_AUDIO;
    audio_stream->codecpar->codec_id = AV_CODEC_ID_AAC;

    avformat_write_header(out_fmt);

    // الآن يمكنك كتابة packets إلى out_fmt
    // av_interleaved_write_frame(out_fmt, pkt) يجمع الحزم تلقائيًا

    av_write_trailer(out_fmt);
    avformat_free_context(out_fmt);
    return 0;
}

